INSERT INTO `categories` (`id`, `event_id`, `tenant_id`, `name`, `description`, `created_by`, `display_order`, `created_at`, `updated_at`) VALUES
(167, 44, 22, 'Category', '', 17, 0, '2025-10-17 00:42:03', '2025-10-17 00:42:03'),
(206, 46, 32, 'Choral Music', 'This discipline involves group singing in harmony, emphasizing teamwork, vocal discipline, and cultural identity. Performing the National Anthem in Ewe promotes linguistic diversity and national unity while showcasing musical artistry and respect for Ghana’s indigenous languages.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(207, 46, 32, 'Dance', 'Dance expresses culture through movement, rhythm, and storytelling. Participants perform traditional or contemporary dances that reflect community life, values, and celebrations. It helps preserve cultural heritage and fosters appreciation for Ghana’s ethnic diversity.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(208, 46, 32, 'Drama', 'Drama involves acting out stories or real-life situations to educate, entertain, or inspire audiences. It encourages creativity, confidence, and moral reflection. Performances often address social issues, traditional wisdom, or national themes, making it a tool for both cultural preservation and education.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(209, 46, 32, 'Drum Language', 'Drumming serves as a traditional means of communication and artistic expression. Participants interpret and perform rhythms that convey messages, emotions, or ceremonial significance. It highlights the symbolic role of drums in African heritage and the artistry involved in rhythm and coordination.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(210, 46, 32, 'Poetry Performance', 'This discipline blends literary creativity with performance skills. Students recite original or traditional poems that express emotions, cultural pride, and social consciousness. It promotes language proficiency, confidence, and artistic sensitivity.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(211, 46, 32, 'Fashion &amp; Design', 'Fashion and design showcase creativity in clothing and accessories inspired by local culture. Participants display costumes made from traditional fabrics such as kente, batik, or tie-and-dye. It promotes craftsmanship, innovation, and appreciation for indigenous aesthetics.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(212, 46, 32, 'Still Life Drawing', 'Still life drawing involves creating realistic or stylized representations of inanimate objects. It trains learners in observation, composition, proportion, and shading, nurturing patience and attention to detail in visual arts.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(213, 46, 32, 'Figure Drawing', 'This art form focuses on drawing the human form in various poses. It enhances understanding of anatomy, proportion, and movement. In a cultural context, it may depict traditional roles, attire, or daily life activities.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(214, 46, 32, 'Exhibition of Artefacts', 'This involves collecting, displaying, and explaining cultural or historical objects such as tools, ornaments, or artworks. It helps learners appreciate heritage, craftsmanship, and the evolution of cultural identity.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(215, 46, 32, 'Sight Singing', 'Sight singing trains students to read and perform music at first sight without prior rehearsal. It develops musical literacy, listening accuracy, and vocal precision—skills essential for choral and solo performers.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(216, 46, 32, 'Cook Arts', 'This discipline explores culinary creativity rooted in local traditions. Participants prepare indigenous dishes with artistic presentation. It promotes nutrition education, cultural preservation, and practical life skills.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(217, 46, 32, 'Talent Hunk', 'Talent Hunk offers a platform for individuals to showcase unique talents such as playing instruments, spoken word, painting, or comedy. It encourages self-expression, innovation, and confidence among participants.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(218, 46, 32, 'Ampe', 'Ampe is a traditional Ghanaian game played mostly by girls involving clapping, jumping, and rhythm. It combines play, exercise, and performance, highlighting communal spirit, coordination, and cultural recreation.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
(219, 46, 32, 'Story-telling', 'torytelling is a traditional oral art form that conveys morals, history, and wisdom through narratives. Participants use expression, gestures, and local languages to engage audiences. It preserves folklore and strengthens communication skills.', 27, 0, '2025-10-19 21:16:15', '2025-10-19 21:16:15'),
