(2031, 'be27b1bbef7d416e941066d7c49155e1', '233541677638', 'confirm_vote', '{\"service_code\":\"711*999\",\"ussd_code\":\"999\",\"selected_event\":{\"id\":50,\"tenant_id\":37,\"name\":\"MANUEL GMT AWARDS 2025\",\"code\":\"MANUELGMTA\",\"description\":\"This award is organised to encourage individuals to learn how to invest, make money and also take advantage of of the technological we are\",\"featured_image\":\"public\\/uploads\\/events\\/events_6925f58e07b13.jpg\",\"start_date\":\"2025-11-30 18:20:00\",\"end_date\":\"2025-11-30 18:20:00\",\"vote_price\":\"1.00\",\"active\":1,\"status\":\"active\",\"visibility\":\"public\",\"admin_status\":\"pending\",\"admin_notes\":null,\"created_by\":32,\"suspended_reason\":null,\"suspended_by\":null,\"suspended_at\":null,\"closed_at\":null,\"archived_at\":null,\"created_at\":\"2025-11-25 18:29:34\",\"updated_at\":\"2025-11-25 18:30:30\",\"results_visible\":1,\"deactivated_at\":null,\"deactivated_by\":null},\"selected_category\":{\"id\":274,\"event_id\":50,\"tenant_id\":37,\"name\":\"BUEST FOREX TRADER OF THE YEAR\",\"description\":\"This award recognizes an exceptional trader who has demonstrated outstanding skill, discipline, and consistency throughout the year. The recipient of this award stands out for their ability to analyze the markets with precision, manage risk effectively, and deliver remarkable trading performance over time.\\r\\nThe Best Trader of the Year embodies excellence, professionalism, and a deep understanding of market behavior. This individual showcases not only impressive profitability but also strong decision-making, emotional control, and a commitment to continuous growth. Their trading journey serves as an inspiration to others and reflects the highest standards of dedication and mastery in the financial markets.\",\"created_by\":32,\"display_order\":0,\"created_at\":\"2025-11-25 18:29:34\",\"updated_at\":\"2025-11-25 18:29:34\"},\"selected_contestant\":{\"id\":239,\"tenant_id\":37,\"event_id\":50,\"name\":\"GOMEY MAWULI\",\"contestant_code\":\"T3701\",\"image_url\":null,\"bio\":\"GOMEY MAWULI ,With seven years of dedicated experience in the financial markets, this trader has built a strong reputation for precision, discipline, and consistency. Their journey began with a deep curiosity about market movement and has evolved into a highly refined skill set grounded in technical analysis, price action, and strategic risk management.Over the years, they have navigated multiple market conditions\\u2014from high volatility to steady trends\\u2014developing a trading style that blends patience with sharp analytical insight. Their commitment to continuous learning, data-driven decisions, and emotional control has allowed them to deliver steady results and adapt to ever-changing market dynamics.Beyond personal performance, this trader is passionate about sharing knowledge, inspiring upcoming traders, and promoting responsible trading practices. Their seven-year track record stands as proof of resilience, growth, and mastery\\u2014making them a respected figure in the trading community.\",\"display_order\":0,\"active\":1,\"created_by\":32,\"created_at\":\"2025-11-25 18:29:34\",\"updated_at\":\"2025-11-25 18:29:34\"},\"tenant_id\":37,\"selected_bundle\":{\"id\":\"61\",\"votes\":1,\"price\":1,\"is_custom\":true}}', '2025-11-25 23:35:39', '2025-11-25 18:36:08', 37, '711*999'),
